mapper.select:
select s.score_id as scoreId, s.contest_id as contestId, c.contest_name as contestName, s.enroll_id as enrollId, er.enroll_no as enrollNo, s.user_id as userId, s.participant_id as participantId, p.name as participantName, p.guardian_mobile as guardianMobileMasked, s.score_value as scoreValue, s.award_level as awardLevel, s.rank_no as rankNo, s.import_batch_no as importBatchNo, s.audit_status as auditStatus, s.publish_status as publishStatus, s.publish_time as publishTime, s.remark as remark, s.update_time as updateTime from jst_score_record s left join jst_contest c on c.contest_id = s.contest_id and c.del_flag = '0' left join jst_enroll_record er on er.enroll_id = s.enroll_id and er.del_flag = '0' left join jst_participant p on p.participant_id = s.participant_id and p.del_flag = '0'
s.del_flag = '0'
and s.contest_id = #{contestId}
and p.name like concat('%', #{participantName}, '%')
and s.audit_status = #{auditStatus}
and s.publish_status = #{publishStatus}
and s.audit_status = 'pending'
and s.publish_status = 'published'
and s.publish_status = 'published' and s.remark like '[CORRECTION_REQUESTED]%'
${params.dataScope}
order by s.update_time desc, s.score_id desc

select count(1)
from jst_score_record
where enroll_id = #{enrollId}
  and del_flag = '0'

      and score_id <> #{excludeScoreId}

mapper.insert:
insert into jst_score_record (
    contest_id, enroll_id, user_id, participant_id, score_value, award_level,
    rank_no, import_batch_no, audit_status, publish_status, create_by,
    create_time, update_by, update_time, remark, del_flag
) values (
    #{contestId}, #{enrollId}, #{userId}, #{participantId}, #{scoreValue}, #{awardLevel},
    #{rankNo}, #{importBatchNo}, #{auditStatus}, #{publishStatus}, #{createBy},
    #{createTime}, #{updateBy}, #{updateTime}, #{remark}, #{delFlag}
)

mapper.update:
update jst_score_record
set audit_status = #{targetAuditStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where score_id = #{scoreId}
  and audit_status = #{expectedAuditStatus}
  and publish_status = 'unpublished'
  and del_flag = '0'
